mapper.select:
SELECT COUNT(*)
FROM sign_in_record
WHERE user_id   = #{userId}
  AND sign_date = #{signDate}
  AND deleted_at IS NULL

SELECT sign_date
FROM sign_in_record
WHERE user_id   = #{userId}
  AND sign_date BETWEEN #{monthStart} AND #{monthEnd}
  AND deleted_at IS NULL
ORDER BY sign_date ASC
